      { id: 46, text: "Hệ điều hành Windows 11 yêu cầu máy tính phải có linh kiện bảo mật nào?", options: ["Microphone", "Chip TPM 2.0", "Máy in", "Loa"], correctAnswer: 1, explanation: "Một tiêu chuẩn bảo mật mới cho hệ thống hiện đại.", difficulty: "Hard", topic: "Máy tính & Em", type: "MCQ" },
      { id: 47, text: "Phát biểu sau đây đúng hay sai: Máy tính để bàn tốn ít điện hơn máy tính xách tay.", options: ["Đúng", "Sai"], correctAnswer: 1, explanation: "Máy tính để bàn thường có hiệu suất cao và tiêu thụ nhiều điện hơn.", difficulty: "Medium", topic: "Máy tính & Em", type: "TRUE_FALSE" },
      { id: 48, text: "Thiết bị nào giúp biến hình ảnh từ máy tính ra giấy?", options: ["Máy quét", "Máy in", "Loa", "Chuột"], correctAnswer: 1, explanation: "Máy in kết nối với máy tính để xuất văn bản/hình ảnh.", difficulty: "Easy", topic: "Máy tính & Em", type: "MCQ" },
      { id: 49, text: "Phân loại các thiết bị sau vào nhóm Thiết bị Vào hoặc Thiết bị Ra hoặc Thiết bị Lưu trữ:", items: ["Bàn phím", "Màn hình", "Ổ cứng SSD", "Loa"], targets: ["Vào", "Ra", "Lưu trữ"], correctAnswer: { "Bàn phím": "Vào", "Màn hình": "Ra", "Loa": "Ra", "Ổ cứng SSD": "Lưu trữ" }, explanation: "Hiểu sâu hơn về luồng dữ liệu trong hệ thống.", difficulty: "Medium", topic: "Máy tính & Em", type: "DRAG_DROP" },
      { id: 50, text: "Chúc mừng em hoàn thành 50 câu về máy tính! Tin học có thú vị không em?", options: ["Có", "Rất thú vị", "Em sẽ học thật giỏi", "Tất cả các ý trên"], correctAnswer: 3, explanation: "Tiếp tục khám phá thế giới công nghệ nhé!", difficulty: "Easy", topic: "Máy tính & Em", type: "MCQ" }
